import{_ as a,o as t,c as r,a0 as n}from"./chunks/framework.jwovEGr5.js";const i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",d=JSON.parse('{"title":"Accept a Premium Offer (Leader)","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/accept-grant.md","filePath":"subscriptions/accept-grant.md"}'),o={name:"subscriptions/accept-grant.md"};function l(s,e,c,h,g,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="accept-a-premium-offer-leader" tabindex="-1">Accept a Premium Offer (Leader) <a class="header-anchor" href="#accept-a-premium-offer-leader" aria-label="Permalink to &quot;Accept a Premium Offer (Leader)&quot;">​</a></h1><p>When your King shares the kingdom&#39;s premium plan with your alliance, it arrives as a <strong><a href="./../getting-started/glossary.html#grant">grant</a></strong> offer that you must <strong>accept</strong> before it does anything. This guide is for <strong>Alliance Leaders and Co-Leaders</strong>.</p><blockquote><p><strong>Your alliance does not become premium automatically just because your kingdom is premium.</strong> The King has to offer a grant, and you have to accept it. Until you accept, your alliance stays on whatever plan it already has (its own, or the free tier). This is the single most common point of confusion — see <a href="./effective-plan.html">Which Plan Applies to You</a>.</p></blockquote><h2 id="finding-your-offer" tabindex="-1">Finding your offer <a class="header-anchor" href="#finding-your-offer" aria-label="Permalink to &quot;Finding your offer&quot;">​</a></h2><p>Grant offers show up on your <strong><a href="./../how-to/my-alliance.html">My Alliance</a></strong> page. A pending offer appears with <strong>Accept</strong> and <strong>Reject</strong> options.</p><p><img src="'+i+'" alt="Grant offer on the My Alliance page"></p><h2 id="accepting" tabindex="-1">Accepting <a class="header-anchor" href="#accepting" aria-label="Permalink to &quot;Accepting&quot;">​</a></h2><ol><li>Open <strong>My Alliance</strong>.</li><li>Find the pending grant offer.</li><li>Select <strong>Accept</strong>.</li></ol><p>Once accepted:</p><ul><li>Your <a href="./effective-plan.html">effective plan</a> becomes the kingdom&#39;s plan, and your usage panel&#39;s <strong>plan source</strong> shows <strong>&quot;Accepted kingdom grant&quot;</strong>.</li><li>Your limits rise to what the grant provides (or to the <strong><a href="./allocations.html">allocation</a></strong> your King set aside for you, if they set one).</li><li>The premium <strong>features the grant carries</strong> switch on.</li></ul><h2 id="rejecting" tabindex="-1">Rejecting <a class="header-anchor" href="#rejecting" aria-label="Permalink to &quot;Rejecting&quot;">​</a></h2><p>If you don&#39;t want the offer, select <strong>Reject</strong>. Nothing changes for your alliance, and the King can see it was declined. They can offer again later if needed.</p><h2 id="which-features-do-i-actually-get" tabindex="-1">Which features do I actually get? <a class="header-anchor" href="#which-features-do-i-actually-get" aria-label="Permalink to &quot;Which features do I actually get?&quot;">​</a></h2><p>A grant passes down only the <strong>shareable</strong> premium features the kingdom plan carries — not necessarily everything. So a granted alliance may get a subset of what a directly-subscribed premium alliance would have. Check your Subscription &amp; Usage panel and the <a href="./premium-features.html">Premium Features</a> page to see what&#39;s active for you.</p><p>One feature worth calling out: <strong>Granted Kingdom Analytics</strong> (the ability to see aggregate kingdom analytics) only appears if the grant you accepted specifically includes that feature. If your kingdom&#39;s plan doesn&#39;t carry it, accepting a grant won&#39;t unlock the kingdom analytics view — and that&#39;s expected, not a bug.</p><h2 id="giving-a-grant-back" tabindex="-1">Giving a grant back <a class="header-anchor" href="#giving-a-grant-back" aria-label="Permalink to &quot;Giving a grant back&quot;">​</a></h2><p>If you no longer want the granted premium, your alliance can give it back (and the King can also revoke it from their side). When a grant ends:</p><ul><li>Your alliance returns to its own plan or the free tier.</li><li>Any allocations tied to the grant are removed.</li></ul><p>See the King&#39;s side of this in <a href="./kingdom-grants.html">Kingdom Grants</a>.</p><h2 id="if-premium-didn-t-turn-on" tabindex="-1">If premium didn&#39;t turn on <a class="header-anchor" href="#if-premium-didn-t-turn-on" aria-label="Permalink to &quot;If premium didn&#39;t turn on&quot;">​</a></h2><p>Check these in order:</p><ol><li><strong>Did you accept?</strong> A pending offer does nothing until accepted. Look on <a href="./../how-to/my-alliance.html">My Alliance</a>.</li><li><strong>What does your plan source say?</strong> If it still reads <em>Free tier</em> or <em>Direct alliance plan</em>, the grant isn&#39;t active. See <a href="./effective-plan.html">Which Plan Applies to You</a>.</li><li><strong>Missing a specific feature?</strong> Grants only carry shareable features; the one you want may not be included. See <a href="./premium-features.html">Premium Features</a>.</li></ol><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./effective-plan.html">Which Plan Applies to You</a> — confirm the grant took effect.</li><li><a href="./premium-features.html">Premium Features</a> — what unlocked.</li><li><a href="./direct-alliance-subscription.html">Direct Alliance Subscriptions</a> — the alternative: your own plan.</li></ul>',24)])])}const f=a(o,[["render",l]]);export{d as __pageData,f as default};
